(() => {
    interface ICircularDeep {
      name: string;
      big: bigint;
      embedded: {hello: string; child?: ICircularDeep};
    }
    interface ICircularDate {
      date: Date;
      month: number;
      year: number;
      embedded?: ICircularDate;
      deep?: ICircularDeep;
    }
    interface RootCircular {
      isRoot: true;
      ciChild: ICircularDeep;
      ciRoort?: RootCircular;
      ciDate: ICircularDate;
    }
    return {build: () => createValidate<RootCircular>(), buildErrors: () => noErrs(createGetValidationErrors<RootCircular>())};
  })()

c(z.lazy(() => {
    const ciDeep: z.ZodType = z.object({
      name: z.string(),
      big: z.bigint(),
      embedded: z.object({hello: z.string(), child: z.lazy(() => ciDeep).optional()}),
    });
    const ciDate: z.ZodType = z.object({
      date: z.date(),
      month: z.number().finite(),
      year: z.number().finite(),
      embedded: z.lazy(() => ciDate).optional(),
    });
    const root: z.ZodType = z.object({
      isRoot: z.literal(true),
      ciChild: ciDeep,
      ciDate: ciDate,
      ciRoort: z.lazy(() => root).optional(),
    });
    return root;
  }))

c(
    (() => {
      const ICircularDeep = Type.Recursive((This) =>
        Type.Object({
          name: Type.String(),
          big: Type.BigInt(),
          embedded: Type.Object({hello: Type.String(), child: Type.Optional(This)}),
        })
      );
      const ICircularDate = Type.Recursive((This) =>
        Type.Object({
          date: Type.Date(),
          month: Type.Number(),
          year: Type.Number(),
          embedded: Type.Optional(This),
        })
      );
      return Type.Recursive((This) =>
        Type.Object({
          isRoot: Type.Literal(true),
          ciChild: ICircularDeep,
          ciDate: ICircularDate,
          ciRoort: Type.Optional(This),
        })
      );
    })()
  )
